catalog_script_client.script:
function onSubmit() {
    var isValid = true;
    var errorMessages = [];

    // Email validation
    var email = g_form.getValue('email');
    if (!email) {
        errorMessages.push('Email address is required');
        isValid = false;
    }

    // Mobile validation
    var mobile = g_form.getValue('mobile_number');
    if (!mobile) {
        errorMessages.push('Mobile number is required');
        isValid = false;
    }

    // Policy number validation
    var policyNumber = g_form.getValue('policy_number');
    if (!policyNumber) {
        errorMessages.push('Policy number is required');
        isValid = false;
    }

    // Vehicle number validation
    var vehicleNumber = g_form.getValue('vehicle_number');
    if (!vehicleNumber) {
        errorMessages.push('Vehicle number is required');
        isValid = false;
    }

    if (!isValid) {
        g_form.addErrorMessage('Please complete all required fields:\n' + errorMessages.join('\n'));
    }

    return isValid;
}
